using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private ITransformer? _model;
    private PredictionEngine<TicketData, TicketPrediction>? _predictionEngine;
    private readonly string _dataPath;
    private readonly string _modelPath;
    private string[] _categoryLabels = [];
    private readonly object _lock = new();

    public bool IsModelTrained => _model is not null;

    public TicketClassifierService(IWebHostEnvironment env)
    {
        _mlContext = new MLContext(seed: 42);
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
    }

    public TrainingResponse Train()
    {
        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var pipeline = _mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features", "SubjectFeatures", "DescriptionFeatures", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        // Cross-validation for evaluation metrics
        var cvResults = _mlContext.MulticlassClassification.CrossValidate(dataView, pipeline, numberOfFolds: 3);
        var avgMetrics = new EvaluationMetrics
        {
            MacroAccuracy = cvResults.Average(r => r.Metrics.MacroAccuracy),
            MicroAccuracy = cvResults.Average(r => r.Metrics.MicroAccuracy),
            LogLoss = cvResults.Average(r => r.Metrics.LogLoss),
            LogLossReduction = cvResults.Average(r => r.Metrics.LogLossReduction),
            PerCategoryMetrics = GetPerCategoryMetrics(cvResults)
        };

        // Train final model on all data
        lock (_lock)
        {
            _model = pipeline.Fit(dataView);
            _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);

            // Extract category labels from the model
            var labelBuffer = new VBuffer<ReadOnlyMemory<char>>();
            _model.GetOutputSchema(dataView.Schema)["Score"]
                .GetSlotNames(ref labelBuffer);
            _categoryLabels = labelBuffer.DenseValues().Select(v => v.ToString()).ToArray();

            _mlContext.Model.Save(_model, dataView.Schema, _modelPath);
        }

        return new TrainingResponse
        {
            Status = "Model trained successfully",
            Metrics = avgMetrics
        };
    }

    public PredictionResponse? Predict(TicketRequest request)
    {
        lock (_lock)
        {
            if (_predictionEngine is null)
                return null;

            var ticketData = new TicketData
            {
                Subject = request.Subject,
                Description = request.Description,
                Priority = request.Priority
            };

            var prediction = _predictionEngine.Predict(ticketData);

            var confidence = new Dictionary<string, float>();
            for (int i = 0; i < _categoryLabels.Length && i < prediction.Score.Length; i++)
            {
                confidence[_categoryLabels[i]] = prediction.Score[i];
            }

            return new PredictionResponse
            {
                PredictedCategory = prediction.Category,
                Confidence = confidence
            };
        }
    }

    private List<CategoryMetric> GetPerCategoryMetrics(
        IReadOnlyList<Microsoft.ML.TrainCatalogBase.CrossValidationResult<Microsoft.ML.Data.MulticlassClassificationMetrics>> cvResults)
    {
        var metrics = new List<CategoryMetric>();
        var first = cvResults.FirstOrDefault()?.Metrics.PerClassLogLoss;
        if (first is null) return metrics;

        for (int i = 0; i < first.Count; i++)
        {
            metrics.Add(new CategoryMetric
            {
                Category = $"Class {i}",
                Precision = cvResults.Average(r => i < r.Metrics.PerClassLogLoss.Count ? 1.0 - r.Metrics.PerClassLogLoss[i] : 0),
                Recall = cvResults.Average(r => r.Metrics.MacroAccuracy),
                F1Score = cvResults.Average(r => r.Metrics.MacroAccuracy)
            });
        }

        return metrics;
    }
}

